import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';

const API_BASE = 'http://localhost:5001/api';

// ========== STYLES ==========
const S = {
  page: { background: '#fff', borderRadius: 10, border: '1.5px solid #e2e8f0', marginBottom: 16, overflow: 'hidden' },
  pageHeader: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 18px', cursor: 'pointer', userSelect: 'none' },
  pageTitle: { margin: 0, fontSize: 15, fontWeight: 700 },
  pageBody: { padding: '12px 18px 18px', borderTop: '1px solid #f1f5f9' },
  grid2: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px 18px' },
  grid3: { display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '10px 18px' },
  grid4: { display: 'grid', gridTemplateColumns: '1fr 1fr 1fr 1fr', gap: '8px 14px' },
  label: { display: 'block', fontSize: 11, fontWeight: 600, color: '#475569', marginBottom: 3 },
  input: { width: '100%', padding: '7px 10px', border: '1.5px solid #e2e8f0', borderRadius: 6, fontSize: 13, outline: 'none', boxSizing: 'border-box', transition: 'border-color 0.2s' },
  select: { width: '100%', padding: '7px 10px', border: '1.5px solid #e2e8f0', borderRadius: 6, fontSize: 13, outline: 'none', boxSizing: 'border-box', background: '#fff' },
  section: { marginBottom: 14 },
  sectionTitle: { fontSize: 13, fontWeight: 700, color: '#1e293b', margin: '0 0 8px', padding: '4px 0', borderBottom: '1px solid #f1f5f9' },
  okBadge: { display: 'inline-block', background: '#10b98122', color: '#059669', padding: '2px 10px', borderRadius: 4, fontSize: 11, fontWeight: 700, cursor: 'pointer', border: '1px solid #10b98144' },
  ngBadge: { display: 'inline-block', background: '#ef444422', color: '#dc2626', padding: '2px 10px', borderRadius: 4, fontSize: 11, fontWeight: 700, cursor: 'pointer', border: '1px solid #ef444444' },
};

function Field({ label, name, type = 'text', value, onChange, placeholder, unit, min, max, step, options, style }) {
  return (
    <div style={style}>
      <label style={S.label}>{label} {unit && <span style={{ color: '#94a3b8', fontWeight: 400 }}>({unit})</span>}</label>
      {options ? (
        <select style={S.select} value={value || ''} onChange={e => onChange(name, e.target.value)}>
          <option value="">Select</option>
          {options.map(o => <option key={o} value={o}>{o}</option>)}
        </select>
      ) : (
        <input style={S.input} type={type} value={value || ''} onChange={e => onChange(name, type === 'number' ? (e.target.value === '' ? '' : parseFloat(e.target.value)) : e.target.value)}
          placeholder={placeholder || ''} min={min} max={max} step={step || (type === 'number' ? '0.01' : undefined)}
          onFocus={e => { e.target.style.borderColor = '#3b82f6'; }} onBlur={e => { e.target.style.borderColor = '#e2e8f0'; }} />
      )}
    </div>
  );
}

function OKField({ label, name, value, onChange }) {
  const isOk = value !== 'NG';
  return (
    <div>
      <label style={S.label}>{label}</label>
      <span style={isOk ? S.okBadge : S.ngBadge} onClick={() => onChange(name, isOk ? 'NG' : 'OK')}>
        {isOk ? '✅ OK' : '❌ NG'}
      </span>
    </div>
  );
}

function PageSection({ number, title, icon, color, children, open, onToggle }) {
  return (
    <div style={{ ...S.page, borderColor: open ? color + '88' : '#e2e8f0' }}>
      <div style={{ ...S.pageHeader, background: open ? color + '0d' : '#fafbfc' }} onClick={onToggle}>
        <h3 style={{ ...S.pageTitle, color: open ? color : '#334155' }}>{icon} Page {number}: {title}</h3>
        <span style={{ fontSize: 18, color: '#94a3b8' }}>{open ? '▼' : '▶'}</span>
      </div>
      {open && <div style={S.pageBody}>{children}</div>}
    </div>
  );
}

// ========== SERIAL INPUT ==========
function SerialInput({ serials, setSerials, page, stage }) {
  const [input, setInput] = useState('');
  const add = () => {
    const val = input.trim();
    if (val && !serials.find(s => s.serial_number === val && s.page_number === page)) {
      setSerials([...serials, { serial_number: val, page_number: page, stage }]);
      setInput('');
    }
  };
  const remove = (idx) => setSerials(serials.filter((_, i) => i !== idx));
  const pageSerials = serials.filter(s => s.page_number === page);

  return (
    <div style={{ marginTop: 8 }}>
      <label style={S.label}>Serial Numbers — {stage}</label>
      <div style={{ display: 'flex', gap: 6 }}>
        <input style={{ ...S.input, flex: 1 }} value={input} onChange={e => setInput(e.target.value)}
          placeholder="GS04830..." onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), add())} />
        <button onClick={add} style={{ padding: '6px 14px', background: '#3b82f6', color: '#fff', border: 'none', borderRadius: 6, cursor: 'pointer', fontSize: 12, fontWeight: 600 }}>+ Add</button>
      </div>
      {pageSerials.length > 0 && (
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginTop: 6 }}>
          {pageSerials.map((s, i) => {
            const globalIdx = serials.indexOf(s);
            return (
              <span key={i} style={{ background: '#eff6ff', border: '1px solid #bfdbfe', borderRadius: 4, padding: '2px 8px', fontSize: 11, display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                {s.serial_number}
                <span style={{ cursor: 'pointer', color: '#ef4444', fontWeight: 700 }} onClick={() => remove(globalIdx)}>×</span>
              </span>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ========== MAIN FORM ==========
function IPQCFormPage() {
  const [form, setForm] = useState({
    date: new Date().toISOString().split('T')[0],
    shift: 'Day',
    line: 'A',
    time: new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }),
    po_number: '',
    inspector_name: '',
    source: 'form',
  });
  const [serials, setSerials] = useState([]);
  const [openPages, setOpenPages] = useState({ 1: true });
  const [saving, setSaving] = useState(false);
  const [saveResult, setSaveResult] = useState(null);
  const [savedList, setSavedList] = useState([]);
  const [loadingList, setLoadingList] = useState(false);
  const [viewMode, setViewMode] = useState('form'); // 'form' | 'list' | 'view'
  const [viewData, setViewData] = useState(null);
  const [stats, setStats] = useState(null);

  const set = (name, value) => setForm(prev => ({ ...prev, [name]: value }));
  const toggle = (pg) => setOpenPages(prev => ({ ...prev, [pg]: !prev[pg] }));

  const loadList = useCallback(async () => {
    setLoadingList(true);
    try {
      const res = await axios.get(`${API_BASE}/ipqc-data/list`);
      if (res.data.success) setSavedList(res.data.data || []);
    } catch (e) { console.error(e); }
    finally { setLoadingList(false); }
  }, []);

  const loadStats = useCallback(async () => {
    try {
      const res = await axios.get(`${API_BASE}/ipqc-data/stats`);
      if (res.data.success) setStats(res.data.stats);
    } catch (e) { console.error(e); }
  }, []);

  useEffect(() => { loadList(); loadStats(); }, [loadList, loadStats]);

  const handleSave = async () => {
    if (!form.date || !form.shift || !form.line) { alert('Date, Shift, Line are required!'); return; }
    setSaving(true); setSaveResult(null);
    try {
      const payload = { ...form, serials };
      const res = await axios.post(`${API_BASE}/ipqc-data/save`, payload);
      if (res.data.success) {
        setSaveResult({ type: 'success', msg: `Checksheet #${res.data.id} saved successfully!` });
        loadList(); loadStats();
      } else {
        setSaveResult({ type: 'error', msg: res.data.error || 'Save failed' });
      }
    } catch (e) {
      setSaveResult({ type: 'error', msg: e.response?.data?.error || e.message });
    } finally { setSaving(false); }
  };

  const handleView = async (id) => {
    try {
      const res = await axios.get(`${API_BASE}/ipqc-data/get/${id}`);
      if (res.data.success) { setViewData(res.data.data); setViewMode('view'); }
    } catch (e) { alert('Error loading: ' + e.message); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this checksheet?')) return;
    try {
      await axios.delete(`${API_BASE}/ipqc-data/delete/${id}`);
      loadList(); loadStats();
    } catch (e) { alert('Error: ' + e.message); }
  };

  const resetForm = () => {
    setForm({
      date: new Date().toISOString().split('T')[0],
      shift: 'Day', line: 'A',
      time: new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }),
      po_number: '', inspector_name: '', source: 'form',
    });
    setSerials([]);
    setSaveResult(null);
    setOpenPages({ 1: true });
  };

  // ========== LIST VIEW ==========
  if (viewMode === 'list') {
    return (
      <div>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
          <h2 style={{ margin: 0, fontSize: 18 }}>📋 Saved IPQC Checksheets</h2>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={() => setViewMode('form')} style={btnStyle('#3b82f6')}>+ New Checksheet</button>
            <button onClick={loadList} disabled={loadingList} style={btnStyle('#64748b')}>{loadingList ? '⏳' : '🔄'} Refresh</button>
          </div>
        </div>

        {stats && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))', gap: 10, marginBottom: 16 }}>
            <StatCard icon="📊" label="Total" value={stats.total} color="#3b82f6" />
            <StatCard icon="📝" label="From Form" value={stats.fromForm} color="#8b5cf6" />
            <StatCard icon="🤖" label="From OCR" value={stats.fromOCR} color="#06b6d4" />
            <StatCard icon="✅" label="Genuine" value={stats.genuine} color="#10b981" />
            <StatCard icon="⚠️" label="Suspicious" value={stats.suspicious} color="#f59e0b" />
            <StatCard icon="📅" label="Dates" value={stats.uniqueDates} color="#64748b" />
          </div>
        )}

        {savedList.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 40, color: '#94a3b8' }}>
            <div style={{ fontSize: 40 }}>📭</div>
            <p>No checksheets saved yet. Click "New Checksheet" to start.</p>
          </div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
              <thead>
                <tr style={{ background: '#f8fafc' }}>
                  <th style={thS}>#</th><th style={thS}>Date</th><th style={thS}>Line</th><th style={thS}>Shift</th>
                  <th style={thS}>Source</th><th style={thS}>Inspector</th><th style={thS}>Serials</th>
                  <th style={thS}>Fraud</th><th style={thS}>Created</th><th style={thS}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {savedList.map((row, idx) => (
                  <tr key={row.id} style={{ background: idx % 2 ? '#fafbfc' : '#fff' }}>
                    <td style={tdS}>{row.id}</td>
                    <td style={tdS}>{row.date}</td>
                    <td style={tdS}><span style={{ background: '#eff6ff', color: '#2563eb', padding: '2px 8px', borderRadius: 4, fontSize: 11, fontWeight: 600 }}>Line {row.line}</span></td>
                    <td style={tdS}><span style={{ fontSize: 11 }}>{row.shift === 'Day' ? '☀️' : '🌙'} {row.shift}</span></td>
                    <td style={tdS}><span style={{ background: row.source === 'form' ? '#f3e8ff' : '#ecfdf5', color: row.source === 'form' ? '#7c3aed' : '#059669', padding: '2px 6px', borderRadius: 3, fontSize: 10, fontWeight: 600 }}>{row.source === 'form' ? '📝 Form' : '🤖 OCR'}</span></td>
                    <td style={tdS}>{row.inspector_name || '—'}</td>
                    <td style={tdS}>{row.serial_count || 0}</td>
                    <td style={tdS}>{row.fraud_verdict ? <FraudBadge verdict={row.fraud_verdict} /> : '—'}</td>
                    <td style={{ ...tdS, fontSize: 11 }}>{row.created_at}</td>
                    <td style={tdS}>
                      <div style={{ display: 'flex', gap: 4 }}>
                        <button onClick={() => handleView(row.id)} style={smallBtn('#3b82f6')}>👁</button>
                        <button onClick={() => handleDelete(row.id)} style={smallBtn('#ef4444')}>🗑</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    );
  }

  // ========== VIEW MODE ==========
  if (viewMode === 'view' && viewData) {
    return (
      <div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
          <button onClick={() => setViewMode('list')} style={btnStyle('#64748b')}>← Back</button>
          <h2 style={{ margin: 0, fontSize: 18 }}>📊 Checksheet #{viewData.id} — {viewData.date} | Line {viewData.line} | {viewData.shift}</h2>
        </div>
        <div style={{ background: '#fff', borderRadius: 10, border: '1.5px solid #e2e8f0', padding: 20 }}>
          <div style={S.grid3}>
            <ViewField label="Date" value={viewData.date} />
            <ViewField label="Shift" value={viewData.shift} />
            <ViewField label="Line" value={viewData.line} />
            <ViewField label="Time" value={viewData.time} />
            <ViewField label="PO Number" value={viewData.po_number} />
            <ViewField label="Inspector" value={viewData.inspector_name} />
            <ViewField label="Source" value={viewData.source} />
            <ViewField label="Fraud Verdict" value={viewData.fraud_verdict} />
            <ViewField label="Fraud Score" value={viewData.fraud_score} />
          </div>
          <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
          <h4 style={{ fontSize: 14, color: '#1e293b' }}>📏 Page 1 — Shop Floor & Stringer</h4>
          <div style={S.grid4}>
            <ViewField label="Shop Floor Temp" value={viewData.shop_floor_temp} unit="°C" />
            <ViewField label="Humidity" value={viewData.shop_floor_humidity} unit="%" />
            <ViewField label="Soldering Temp" value={viewData.soldering_temp} unit="°C" />
            <ViewField label="Cell Efficiency" value={viewData.cell_efficiency} unit="%" />
          </div>
          <div style={{ ...S.grid4, marginTop: 8 }}>
            <ViewField label="Cell Gap TS01A" value={viewData.cell_gap_ts01a} unit="mm" />
            <ViewField label="Cell Gap TS01B" value={viewData.cell_gap_ts01b} unit="mm" />
            <ViewField label="Cell Gap TS02A" value={viewData.cell_gap_ts02a} unit="mm" />
            <ViewField label="Cell Gap TS02B" value={viewData.cell_gap_ts02b} unit="mm" />
            <ViewField label="Cell Gap TS03A" value={viewData.cell_gap_ts03a} unit="mm" />
            <ViewField label="Cell Gap TS03B" value={viewData.cell_gap_ts03b} unit="mm" />
            <ViewField label="Cell Gap TS04A" value={viewData.cell_gap_ts04a} unit="mm" />
            <ViewField label="Cell Gap TS04B" value={viewData.cell_gap_ts04b} unit="mm" />
          </div>
          <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
          <h4 style={{ fontSize: 14, color: '#1e293b' }}>📐 Page 2 — Layout & Dimensions</h4>
          <div style={S.grid4}>
            <ViewField label="Edge-Top" value={viewData.cell_edge_glass_top} unit="mm" />
            <ViewField label="Edge-Bottom" value={viewData.cell_edge_glass_bottom} unit="mm" />
            <ViewField label="Edge-Sides" value={viewData.cell_edge_glass_sides} unit="mm" />
            <ViewField label="String-String Gap" value={viewData.string_to_string_gap} unit="mm" />
            <ViewField label="Busbar-Cell" value={viewData.terminal_busbar_to_cell} unit="mm" />
            <ViewField label="Creepage Top" value={viewData.creepage_top} unit="mm" />
            <ViewField label="Creepage Bottom" value={viewData.creepage_bottom} unit="mm" />
            <ViewField label="Creepage Left" value={viewData.creepage_left} unit="mm" />
          </div>
          <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
          <h4 style={{ fontSize: 14, color: '#1e293b' }}>🔧 Page 3 — Pre-Lamination</h4>
          <div style={S.grid4}>
            <ViewField label="Hole 1" value={viewData.hole1_dimension} unit="mm" />
            <ViewField label="Hole 2" value={viewData.hole2_dimension} unit="mm" />
            <ViewField label="Hole 3" value={viewData.hole3_dimension} unit="mm" />
            <ViewField label="Solder Iron 1" value={viewData.soldering_iron_temp1} unit="°C" />
            <ViewField label="Solder Iron 2" value={viewData.soldering_iron_temp2} unit="°C" />
          </div>
          <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
          <h4 style={{ fontSize: 14, color: '#1e293b' }}>📦 Page 4-5 — Post-Lam & JB</h4>
          <div style={S.grid4}>
            <ViewField label="Anodizing" value={viewData.anodizing_thickness} unit="micron" />
            <ViewField label="Glue Weight" value={viewData.short_side_glue_weight} unit="gm" />
            <ViewField label="Long Side Glue" value={viewData.long_side_glue_weight} unit="gm" />
            <ViewField label="Silicon Glue" value={viewData.silicon_glue_weight} unit="gm" />
            <ViewField label="Welding Current" value={viewData.welding_current} unit="Amp" />
            <ViewField label="Potting Weight" value={viewData.potting_weight} unit="gm" />
            <ViewField label="Curing Temp" value={viewData.curing_temp} unit="°C" />
            <ViewField label="Curing Humidity" value={viewData.curing_humidity} unit="%" />
          </div>
          <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
          <h4 style={{ fontSize: 14, color: '#1e293b' }}>⚡ Page 6-7 — Testing & Final</h4>
          <div style={S.grid4}>
            <ViewField label="Ambient Temp" value={viewData.ambient_temp} unit="°C" />
            <ViewField label="Module Temp" value={viewData.module_temp} unit="°C" />
            <ViewField label="DCW 1" value={viewData.dcw_value1} unit="mA" />
            <ViewField label="DCW 2" value={viewData.dcw_value2} unit="mA" />
            <ViewField label="IR 1" value={viewData.ir_value1} unit="mΩ" />
            <ViewField label="IR 2" value={viewData.ir_value2} unit="mΩ" />
            <ViewField label="Voltage" value={viewData.voltage_verification} unit="V" />
            <ViewField label="Current" value={viewData.current_verification} unit="A" />
            <ViewField label="Diagonal Diff" value={viewData.diagonal_difference} unit="mm" />
            <ViewField label="Cable Length" value={viewData.cable_length_final} unit="mm" />
            <ViewField label="Module Dim" value={viewData.module_dimension} />
            <ViewField label="Pallet Dim" value={viewData.pallet_dimension} />
          </div>
          {viewData.serials?.length > 0 && (
            <>
              <hr style={{ borderColor: '#f1f5f9', margin: '14px 0' }} />
              <h4 style={{ fontSize: 14, color: '#1e293b' }}>🔢 Serial Numbers ({viewData.serials.length})</h4>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {viewData.serials.map((s, i) => (
                  <span key={i} style={{ background: '#eff6ff', border: '1px solid #bfdbfe', borderRadius: 4, padding: '2px 8px', fontSize: 11 }}>
                    P{s.page_number} {s.serial_number}
                  </span>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    );
  }

  // ========== FORM VIEW ==========
  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
        <h2 style={{ margin: 0, fontSize: 18 }}>📝 IPQC Checksheet — Manual Entry</h2>
        <div style={{ display: 'flex', gap: 8 }}>
          <button onClick={() => { setViewMode('list'); loadList(); }} style={btnStyle('#64748b')}>📋 View All ({savedList.length})</button>
          <button onClick={resetForm} style={btnStyle('#f59e0b')}>🔄 Reset</button>
        </div>
      </div>

      {saveResult && (
        <div style={{ padding: '10px 16px', borderRadius: 8, marginBottom: 12, background: saveResult.type === 'success' ? '#ecfdf5' : '#fef2f2', color: saveResult.type === 'success' ? '#065f46' : '#991b1b', border: `1px solid ${saveResult.type === 'success' ? '#a7f3d0' : '#fca5a5'}`, fontSize: 13 }}>
          {saveResult.type === 'success' ? '✅' : '❌'} {saveResult.msg}
        </div>
      )}

      {/* HEADER — Date/Shift/Line/Time */}
      <div style={{ ...S.page, borderColor: '#3b82f666' }}>
        <div style={{ padding: '14px 18px', background: '#eff6ff' }}>
          <h3 style={{ margin: 0, fontSize: 15, fontWeight: 700, color: '#1e40af' }}>🏭 GAUTAM SOLAR — IPQC Check Sheet</h3>
          <p style={{ margin: '4px 0 0', fontSize: 11, color: '#3b82f6' }}>Document No: GSPL/IPQC/IPC/003</p>
        </div>
        <div style={{ padding: '12px 18px' }}>
          <div style={S.grid4}>
            <Field label="Date" name="date" type="date" value={form.date} onChange={set} />
            <Field label="Shift" name="shift" value={form.shift} onChange={set} options={['Day', 'Night']} />
            <Field label="Line" name="line" value={form.line} onChange={set} options={['A', 'B', 'C', 'D', 'E']} />
            <Field label="Time" name="time" value={form.time} onChange={set} placeholder="HH:MM" />
          </div>
          <div style={{ ...S.grid3, marginTop: 10 }}>
            <Field label="PO Number" name="po_number" value={form.po_number} onChange={set} placeholder="PO Number" />
            <Field label="Inspector Name" name="inspector_name" value={form.inspector_name} onChange={set} placeholder="Checked By" />
            <div />
          </div>
        </div>
      </div>

      {/* PAGE 1 */}
      <PageSection number={1} title="Shop Floor & Stringer" icon="🏭" color="#3b82f6" open={!!openPages[1]} onToggle={() => toggle(1)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>🌡️ Environment</div>
          <div style={S.grid4}>
            <Field label="Shop Floor Temp" name="shop_floor_temp" type="number" value={form.shop_floor_temp} onChange={set} unit="°C" placeholder="25" />
            <Field label="Humidity" name="shop_floor_humidity" type="number" value={form.shop_floor_humidity} onChange={set} unit="%" placeholder="40-60" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🔲 Glass & EVA</div>
          <div style={S.grid3}>
            <Field label="Glass Dimension (L×W×T)" name="glass_dimension" value={form.glass_dimension} onChange={set} placeholder="2274×1126×3.2 mm" />
            <OKField label="Glass Visual" name="glass_visual" value={form.glass_visual} onChange={set} />
            <Field label="EVA/EPE Type" name="eva_epe_type" value={form.eva_epe_type} onChange={set} placeholder="EP-304" />
          </div>
          <div style={{ ...S.grid3, marginTop: 8 }}>
            <Field label="EVA Dimension (L×W×T)" name="eva_epe_dimension" value={form.eva_epe_dimension} onChange={set} placeholder="2272×1128×2.0 mm" />
            <OKField label="EVA Status" name="eva_epe_status" value={form.eva_epe_status} onChange={set} />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🔌 Cell & Soldering</div>
          <div style={S.grid4}>
            <Field label="Soldering Temp" name="soldering_temp" type="number" value={form.soldering_temp} onChange={set} unit="°C" placeholder="400-420" />
            <Field label="Cell Manufacturer" name="cell_manufacturer" value={form.cell_manufacturer} onChange={set} placeholder="Solar Space" />
            <Field label="Cell Efficiency" name="cell_efficiency" type="number" value={form.cell_efficiency} onChange={set} unit="%" placeholder="25.40" />
            <Field label="Cell Size (L×W)" name="cell_size" value={form.cell_size} onChange={set} placeholder="182.34×91.92 mm" />
          </div>
          <div style={{ ...S.grid3, marginTop: 8 }}>
            <OKField label="Cell Condition" name="cell_condition" value={form.cell_condition} onChange={set} />
            <OKField label="Loading Cleanliness" name="cell_loading_cleanliness" value={form.cell_loading_cleanliness || 'OK'} onChange={set} />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>📏 Cell to Cell Gap (per Stringer)</div>
          <div style={S.grid4}>
            <Field label="TS01A" name="cell_gap_ts01a" type="number" value={form.cell_gap_ts01a} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS01B" name="cell_gap_ts01b" type="number" value={form.cell_gap_ts01b} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS02A" name="cell_gap_ts02a" type="number" value={form.cell_gap_ts02a} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS02B" name="cell_gap_ts02b" type="number" value={form.cell_gap_ts02b} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS03A" name="cell_gap_ts03a" type="number" value={form.cell_gap_ts03a} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS03B" name="cell_gap_ts03b" type="number" value={form.cell_gap_ts03b} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS04A" name="cell_gap_ts04a" type="number" value={form.cell_gap_ts04a} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
            <Field label="TS04B" name="cell_gap_ts04b" type="number" value={form.cell_gap_ts04b} onChange={set} unit="mm" placeholder="0.70-0.90" step="0.01" />
          </div>
        </div>
        <div style={{ ...S.grid3, marginTop: 8 }}>
          <OKField label="Stringer Spec" name="stringer_specification" value={form.stringer_specification} onChange={set} />
          <OKField label="TS Visual" name="ts_visual" value={form.ts_visual} onChange={set} />
          <OKField label="TS EL Image" name="ts_el_image" value={form.ts_el_image} onChange={set} />
        </div>
      </PageSection>

      {/* PAGE 2 */}
      <PageSection number={2} title="Soldering & Layout" icon="📐" color="#8b5cf6" open={!!openPages[2]} onToggle={() => toggle(2)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>🔬 Peel Strength</div>
          <div style={S.grid3}>
            <Field label="Ribbon to Cell" name="peel_strength_ribbon_cell" type="number" value={form.peel_strength_ribbon_cell} onChange={set} unit="N" placeholder="≥21" />
            <Field label="Ribbon to Busbar" name="peel_strength_ribbon_busbar" type="number" value={form.peel_strength_ribbon_busbar} onChange={set} unit="N" placeholder="≥22" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>📐 Distances & Gaps</div>
          <div style={S.grid4}>
            <Field label="String-String Gap" name="string_to_string_gap" type="number" value={form.string_to_string_gap} onChange={set} unit="mm" placeholder="1.5" />
            <Field label="Edge-Top" name="cell_edge_glass_top" type="number" value={form.cell_edge_glass_top} onChange={set} unit="mm" placeholder="18.70" />
            <Field label="Edge-Bottom" name="cell_edge_glass_bottom" type="number" value={form.cell_edge_glass_bottom} onChange={set} unit="mm" placeholder="18.58" />
            <Field label="Edge-Sides" name="cell_edge_glass_sides" type="number" value={form.cell_edge_glass_sides} onChange={set} unit="mm" placeholder="12.46" />
          </div>
          <div style={{ ...S.grid4, marginTop: 8 }}>
            <Field label="Busbar to Cell" name="terminal_busbar_to_cell" type="number" value={form.terminal_busbar_to_cell} onChange={set} unit="mm" placeholder="3.04" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>📏 Creepage Distance</div>
          <div style={S.grid4}>
            <Field label="Creepage Top" name="creepage_top" type="number" value={form.creepage_top} onChange={set} unit="mm" placeholder="11.48" />
            <Field label="Creepage Bottom" name="creepage_bottom" type="number" value={form.creepage_bottom} onChange={set} unit="mm" placeholder="10.98" />
            <Field label="Creepage Left" name="creepage_left" type="number" value={form.creepage_left} onChange={set} unit="mm" placeholder="11.24" />
            <Field label="Creepage Right" name="creepage_right" type="number" value={form.creepage_right} onChange={set} unit="mm" placeholder="11.56" />
          </div>
        </div>
        <div style={{ ...S.grid3, marginTop: 8 }}>
          <OKField label="Soldering Quality" name="soldering_quality" value={form.soldering_quality} onChange={set} />
          <OKField label="Auto Taping" name="auto_taping" value={form.auto_taping} onChange={set} />
          <OKField label="RFID/Logo Position" name="rfid_logo_position" value={form.rfid_logo_position} onChange={set} />
        </div>
        <div style={{ ...S.grid3, marginTop: 8 }}>
          <Field label="Back EVA Type" name="back_eva_type" value={form.back_eva_type} onChange={set} placeholder="EP-304" />
          <Field label="Back EVA Dimension" name="back_eva_dimension" value={form.back_eva_dimension} onChange={set} placeholder="2274×1126×0.70 mm" />
          <Field label="Back Glass Dimension" name="back_glass_dimension" value={form.back_glass_dimension} onChange={set} placeholder="2272×1128×2.0 mm" />
        </div>
      </PageSection>

      {/* PAGE 3 */}
      <PageSection number={3} title="Pre-Lamination" icon="🔧" color="#059669" open={!!openPages[3]} onToggle={() => toggle(3)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>🕳️ Holes & Busbar</div>
          <div style={S.grid4}>
            <Field label="Hole 1 Dim" name="hole1_dimension" type="number" value={form.hole1_dimension} onChange={set} unit="mm" placeholder="12±0.5" />
            <Field label="Hole 2 Dim" name="hole2_dimension" type="number" value={form.hole2_dimension} onChange={set} unit="mm" placeholder="12±0.5" />
            <Field label="Hole 3 Dim" name="hole3_dimension" type="number" value={form.hole3_dimension} onChange={set} unit="mm" placeholder="12±0.5" />
            <OKField label="Busbar Flatten" name="busbar_flatten" value={form.busbar_flatten} onChange={set} />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🔥 Soldering Iron</div>
          <div style={S.grid3}>
            <Field label="Solder Iron Temp 1" name="soldering_iron_temp1" type="number" value={form.soldering_iron_temp1} onChange={set} unit="°C" placeholder="400-430" />
            <Field label="Solder Iron Temp 2" name="soldering_iron_temp2" type="number" value={form.soldering_iron_temp2} onChange={set} unit="°C" placeholder="400-430" />
            <Field label="Rework Method" name="rework_method" value={form.rework_method} onChange={set} options={['Manual', 'Auto']} />
          </div>
        </div>
        <div style={S.grid3}>
          <OKField label="Pre-Lam Visual" name="pre_lam_visual" value={form.pre_lam_visual} onChange={set} />
          <OKField label="Rework Station" name="rework_station_clean" value={form.rework_station_clean || 'OK'} onChange={set} />
        </div>
        <SerialInput serials={serials} setSerials={setSerials} page={3} stage="Pre-EL" />
      </PageSection>

      {/* PAGE 4 */}
      <PageSection number={4} title="Post-Lamination & Framing" icon="📦" color="#d97706" open={!!openPages[4]} onToggle={() => toggle(4)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>🧪 Tests & Visual</div>
          <div style={S.grid3}>
            <Field label="Peel EVA-Glass" name="peel_test_eva_glass" value={form.peel_test_eva_glass} onChange={set} placeholder="≥60 N/cm" />
            <Field label="Peel EVA-Backsheet" name="peel_test_eva_backsheet" value={form.peel_test_eva_backsheet} onChange={set} placeholder="≥60 N/cm" />
            <Field label="Gel Content" name="gel_content" value={form.gel_content} onChange={set} placeholder="75-95%" />
          </div>
          <div style={{ ...S.grid4, marginTop: 8 }}>
            <OKField label="Tape Removing" name="tape_removing" value={form.tape_removing} onChange={set} />
            <OKField label="Trimming Quality" name="trimming_quality" value={form.trimming_quality} onChange={set} />
            <OKField label="Trimming Blade" name="trimming_blade_status" value={form.trimming_blade_status} onChange={set} />
            <OKField label="Post-Lam Visual" name="post_lam_visual" value={form.post_lam_visual} onChange={set} />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🖼️ Framing</div>
          <div style={S.grid4}>
            <OKField label="Glue Uniformity" name="glue_uniformity" value={form.glue_uniformity} onChange={set} />
            <Field label="Short Side Glue" name="short_side_glue_weight" type="number" value={form.short_side_glue_weight} onChange={set} unit="gm" placeholder="16.394" step="0.001" />
            <Field label="Long Side Glue" name="long_side_glue_weight" type="number" value={form.long_side_glue_weight} onChange={set} unit="gm" placeholder="" step="0.001" />
            <Field label="Anodizing Thickness" name="anodizing_thickness" type="number" value={form.anodizing_thickness} onChange={set} unit="micron" placeholder="≥15" step="0.1" />
          </div>
        </div>
        <SerialInput serials={serials} setSerials={setSerials} page={4} stage="Post-Lam" />
      </PageSection>

      {/* PAGE 5 */}
      <PageSection number={5} title="JB Assembly & Curing" icon="🔩" color="#dc2626" open={!!openPages[5]} onToggle={() => toggle(5)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>📦 Junction Box</div>
          <div style={S.grid4}>
            <OKField label="JB Appearance" name="jb_appearance" value={form.jb_appearance} onChange={set} />
            <Field label="Cable Length" name="jb_cable_length" type="number" value={form.jb_cable_length} onChange={set} unit="mm" placeholder="300" />
            <Field label="Silicon Glue Wt" name="silicon_glue_weight" type="number" value={form.silicon_glue_weight} onChange={set} unit="gm" placeholder="21±6" step="0.001" />
            <Field label="Welding Current" name="welding_current" type="number" value={form.welding_current} onChange={set} unit="Amp" placeholder="17" />
          </div>
          <div style={{ ...S.grid3, marginTop: 8 }}>
            <OKField label="JB Soldering" name="soldering_quality_jb" value={form.soldering_quality_jb} onChange={set} />
            <Field label="Glue Ratio" name="glue_ratio" value={form.glue_ratio} onChange={set} placeholder="A/B Ratio" />
            <Field label="Potting Weight" name="potting_weight" type="number" value={form.potting_weight} onChange={set} unit="gm" placeholder="21±6" step="0.001" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🌡️ Curing</div>
          <div style={S.grid4}>
            <Field label="Curing Temp" name="curing_temp" type="number" value={form.curing_temp} onChange={set} unit="°C" placeholder="25±3" />
            <Field label="Curing Humidity" name="curing_humidity" type="number" value={form.curing_humidity} onChange={set} unit="%" placeholder="≤50" />
            <Field label="Curing Time" name="curing_time" value={form.curing_time} onChange={set} placeholder="≥4 hours" />
            <OKField label="Buffing" name="buffing_condition" value={form.buffing_condition} onChange={set} />
          </div>
        </div>
        <OKField label="Cleaning Status" name="cleaning_status" value={form.cleaning_status} onChange={set} />
        <SerialInput serials={serials} setSerials={setSerials} page={5} stage="Post-Visual" />
      </PageSection>

      {/* PAGE 6 */}
      <PageSection number={6} title="Flash Tester & EL" icon="⚡" color="#0891b2" open={!!openPages[6]} onToggle={() => toggle(6)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>🌡️ Environment & Calibration</div>
          <div style={S.grid4}>
            <Field label="Ambient Temp" name="ambient_temp" type="number" value={form.ambient_temp} onChange={set} unit="°C" placeholder="27.93" />
            <Field label="Module Temp" name="module_temp" type="number" value={form.module_temp} onChange={set} unit="°C" placeholder="26.48" />
            <OKField label="Calibration" name="simulator_calibration" value={form.simulator_calibration} onChange={set} />
            <OKField label="EL Check" name="el_check" value={form.el_check} onChange={set} />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>⚡ DCW / IR Values</div>
          <div style={S.grid4}>
            <Field label="DCW #1" name="dcw_value1" type="number" value={form.dcw_value1} onChange={set} unit="mA" placeholder="≤50" step="0.001" />
            <Field label="DCW #2" name="dcw_value2" type="number" value={form.dcw_value2} onChange={set} unit="mA" placeholder="≤50" step="0.001" />
            <Field label="DCW #3" name="dcw_value3" type="number" value={form.dcw_value3} onChange={set} unit="mA" placeholder="≤50" step="0.001" />
            <Field label="DCW #4" name="dcw_value4" type="number" value={form.dcw_value4} onChange={set} unit="mA" placeholder="≤50" step="0.001" />
          </div>
          <div style={{ ...S.grid4, marginTop: 8 }}>
            <Field label="IR #1" name="ir_value1" type="number" value={form.ir_value1} onChange={set} unit="MΩ.m²" placeholder=">40" step="0.01" />
            <Field label="IR #2" name="ir_value2" type="number" value={form.ir_value2} onChange={set} unit="MΩ.m²" placeholder=">40" step="0.01" />
            <Field label="IR #3" name="ir_value3" type="number" value={form.ir_value3} onChange={set} unit="MΩ.m²" placeholder=">40" step="0.01" />
            <Field label="IR #4" name="ir_value4" type="number" value={form.ir_value4} onChange={set} unit="MΩ.m²" placeholder=">40" step="0.01" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>🔌 Power Verification</div>
          <div style={S.grid3}>
            <Field label="Voltage" name="voltage_verification" type="number" value={form.voltage_verification} onChange={set} unit="V" placeholder="55.10" step="0.01" />
            <Field label="Current" name="current_verification" type="number" value={form.current_verification} onChange={set} unit="A" placeholder="7.343" step="0.001" />
            <Field label="Mfg Month" name="manufacturing_month" value={form.manufacturing_month} onChange={set} placeholder="February, 2026" />
          </div>
        </div>
        <div style={S.grid3}>
          <OKField label="Post EL Visual" name="post_el_visual" value={form.post_el_visual} onChange={set} />
          <OKField label="RFID Position" name="rfid_position" value={form.rfid_position} onChange={set} />
        </div>
        <SerialInput serials={serials} setSerials={setSerials} page={6} stage="Flash Tester" />
      </PageSection>

      {/* PAGE 7 */}
      <PageSection number={7} title="Final Inspection & Packaging" icon="📦" color="#6366f1" open={!!openPages[7]} onToggle={() => toggle(7)}>
        <div style={S.section}>
          <div style={S.sectionTitle}>📏 Dimensions</div>
          <div style={S.grid3}>
            <Field label="Module Dimension (L×W×T)" name="module_dimension" value={form.module_dimension} onChange={set} placeholder="2278×1134×30 mm" />
            <Field label="Mounting Hole X" name="mounting_hole_x" type="number" value={form.mounting_hole_x} onChange={set} unit="mm" placeholder="1400" />
            <Field label="Mounting Hole Y" name="mounting_hole_y" type="number" value={form.mounting_hole_y} onChange={set} unit="mm" placeholder="1092" />
          </div>
          <div style={{ ...S.grid4, marginTop: 8 }}>
            <Field label="Diagonal Diff" name="diagonal_difference" type="number" value={form.diagonal_difference} onChange={set} unit="mm" placeholder="≤3" step="0.01" />
            <Field label="Corner Gap" name="corner_gap" type="number" value={form.corner_gap} onChange={set} unit="mm" placeholder="0.03" step="0.01" />
            <Field label="Cable Length" name="cable_length_final" type="number" value={form.cable_length_final} onChange={set} unit="mm" placeholder="300" />
          </div>
        </div>
        <div style={S.section}>
          <div style={S.sectionTitle}>📦 Packaging</div>
          <div style={S.grid4}>
            <OKField label="Final Visual" name="final_visual" value={form.final_visual} onChange={set} />
            <OKField label="Backlabel" name="backlabel" value={form.backlabel} onChange={set} />
            <OKField label="Packaging Label" name="packaging_label" value={form.packaging_label} onChange={set} />
            <OKField label="Box Content" name="box_content" value={form.box_content} onChange={set} />
          </div>
          <div style={{ ...S.grid3, marginTop: 8 }}>
            <OKField label="Box Condition" name="box_condition" value={form.box_condition} onChange={set} />
            <Field label="Pallet Dimension" name="pallet_dimension" value={form.pallet_dimension} onChange={set} placeholder="2286×1019×142 mm" />
          </div>
        </div>
        <SerialInput serials={serials} setSerials={setSerials} page={7} stage="Final Visual" />
      </PageSection>

      {/* SUBMIT */}
      <div style={{ display: 'flex', gap: 12, justifyContent: 'center', padding: '20px 0 10px' }}>
        <button onClick={handleSave} disabled={saving}
          style={{ padding: '12px 40px', background: saving ? '#94a3b8' : '#10b981', color: '#fff', border: 'none', borderRadius: 8, fontSize: 15, fontWeight: 700, cursor: saving ? 'default' : 'pointer', boxShadow: '0 2px 8px rgba(16,185,129,0.3)' }}>
          {saving ? '⏳ Saving...' : '💾 Save Checksheet'}
        </button>
        <button onClick={resetForm}
          style={{ padding: '12px 30px', background: '#f1f5f9', color: '#475569', border: '1.5px solid #e2e8f0', borderRadius: 8, fontSize: 15, fontWeight: 600, cursor: 'pointer' }}>
          🔄 Reset
        </button>
      </div>
    </div>
  );
}

// ========== HELPERS ==========
function ViewField({ label, value, unit }) {
  return (
    <div style={{ marginBottom: 4 }}>
      <span style={{ fontSize: 10, color: '#64748b' }}>{label}</span>
      <div style={{ fontSize: 13, fontWeight: 600, color: value ? '#1e293b' : '#cbd5e1' }}>
        {value || '—'}{value && unit ? ` ${unit}` : ''}
      </div>
    </div>
  );
}

function FraudBadge({ verdict }) {
  const c = { GENUINE: '#10b981', NEEDS_REVIEW: '#f59e0b', SUSPICIOUS: '#f97316', LIKELY_DUMMY: '#ef4444' };
  const col = c[verdict] || '#64748b';
  return <span style={{ background: col + '22', color: col, padding: '2px 6px', borderRadius: 3, fontSize: 10, fontWeight: 700, border: `1px solid ${col}44` }}>{verdict}</span>;
}

function StatCard({ icon, label, value, color }) {
  return (
    <div style={{ background: '#fff', borderRadius: 8, border: '1.5px solid #e2e8f0', padding: '12px 14px', display: 'flex', alignItems: 'center', gap: 10 }}>
      <span style={{ fontSize: 22 }}>{icon}</span>
      <div>
        <div style={{ fontSize: 20, fontWeight: 700, color: color || '#1e293b' }}>{value}</div>
        <div style={{ fontSize: 10, color: '#64748b' }}>{label}</div>
      </div>
    </div>
  );
}

const thS = { padding: '8px 10px', textAlign: 'left', borderBottom: '2px solid #e2e8f0', fontSize: 11, color: '#64748b', fontWeight: 600 };
const tdS = { padding: '8px 10px', borderBottom: '1px solid #f1f5f9', fontSize: 12 };
const btnStyle = (bg) => ({ padding: '8px 16px', background: bg, color: '#fff', border: 'none', borderRadius: 6, fontSize: 12, fontWeight: 600, cursor: 'pointer' });
const smallBtn = (bg) => ({ padding: '4px 8px', background: bg + '22', color: bg, border: `1px solid ${bg}44`, borderRadius: 4, fontSize: 11, cursor: 'pointer', fontWeight: 600 });

export default IPQCFormPage;
